final:
module morphological_dilation (
    input [8:0] binary_image, // 3x3 image represented as 9 bits
    output reg dilated_pixel // Output of the dilation operation
);

always @(*) begin
    // Dilation: output is 1 if any input pixel is 1
    dilated_pixel = (binary_image[0] | binary_image[1] | binary_image[2] |
                     binary_image[3] | binary_image[4] | binary_image[5] |
                     binary_image[6] | binary_image[7] | binary_image[8]);
end

endmodule
